import{c as e,Q as o,j as a,m as r}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"HavenBot — issuer playbook","description":"Phrasing for distribute yield, manage KYC, unpause, create checkout links.","frontmatter":{"title":"HavenBot — issuer playbook","description":"Phrasing for distribute yield, manage KYC, unpause, create checkout links."},"headers":[],"relativePath":"havenbot/issuer-playbook.md","filePath":"havenbot/issuer-playbook.md","lastUpdated":1778951051000}'),s={name:"havenbot/issuer-playbook.md"};function d(i,t,n,l,u,c){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="issuer-playbook" tabindex="-1">Issuer playbook <a class="header-anchor" href="#issuer-playbook" aria-label="Permalink to &quot;Issuer playbook&quot;">​</a></h1><p>The issuer-facing surface of HavenBot lands in the same <code>/agent</code> route as the investor one, but five additional tools become visible to <strong>issuer-roled and <code>issuerStatus === &#39;approved&#39;</code></strong> MuHaven wallets: distribute yield, KYC add/remove, unpause a freshly-deployed token, and an audit copilot.</p><p>Every row below follows the same shape: <strong>what you say</strong> → <strong>what the agent calls</strong> → <strong>what you confirm</strong>.</p><blockquote><p><code>&lt;TOKEN&gt;</code> and <code>RWA1</code> are placeholders for whichever token you&#39;re working with — replace them with the actual symbol on your dashboard.</p></blockquote><p>If you don&#39;t see the issuer tools, check:</p><ol><li>You&#39;re signed in with your <strong>issuer passkey</strong> (not your investor passkey — they&#39;re separate per the <a href="/get-started/investor-vs-issuer">one passkey, one role</a> rule).</li><li>Your issuer status is <code>approved</code> (visit <code>/apply-issuer</code> to check).</li></ol><h2 id="distribute-yield" tabindex="-1">Distribute yield <a class="header-anchor" href="#distribute-yield" aria-label="Permalink to &quot;Distribute yield&quot;">​</a></h2><p>The single most common issuer flow. Schedules a yield epoch for a token&#39;s holders.</p><table tabindex="0"><thead><tr><th>You want</th><th>Say</th></tr></thead><tbody><tr><td>Schedule a yield epoch</td><td>&quot;Distribute $50,000 of yield to <code>&lt;TOKEN&gt;</code> holders for May.&quot;</td></tr><tr><td>Quick schedule</td><td>&quot;Distribute $25K to <code>&lt;TOKEN&gt;</code>.&quot; <em>(label defaults to current quarter)</em></td></tr><tr><td>Test the wiring</td><td>&quot;Distribute $1 to <code>&lt;TOKEN&gt;</code> holders.&quot; <em>(useful on testnet)</em></td></tr><tr><td>Per-share rate target</td><td>&quot;Distribute yield to <code>&lt;TOKEN&gt;</code> at $0.0012 per share.&quot;</td></tr><tr><td>Recap last epoch</td><td>&quot;How much did I distribute on <code>&lt;TOKEN&gt;</code> last epoch?&quot;</td></tr></tbody></table><p>Under the hood HavenBot calls <code>muhaven_propose_distribute_yield</code> which triggers the SDK pipeline:</p><ol><li><code>startDistribution</code> — opens the epoch on <code>YieldDistributor</code>.</li><li><code>batchCreate</code> — creates a per-investor <code>MuHavenEscrow</code> (default batch size 50, max 200).</li><li><code>fundEscrows</code> — funds each escrow with the proportional cleartext amount.</li></ol><p>The ConfirmModal shows a multi-leg breakdown. <strong>You sign once</strong> with your issuer passkey; the SDK fans out the batched UserOps.</p><div class="tip custom-block"><p class="custom-block-title">Yield distribution is per-investor at the contract level</p><p>The contract creates a separate <code>MuHavenEscrow</code> per holder, not a single shared pool. This is what makes the per-investor claim privacy-preserving: when an investor later claims, they pull only their escrow — and the operator never knows the amount.</p></div><h2 id="kyc-churn" tabindex="-1">KYC churn <a class="header-anchor" href="#kyc-churn" aria-label="Permalink to &quot;KYC churn&quot;">​</a></h2><table tabindex="0"><thead><tr><th>You want</th><th>Say</th></tr></thead><tbody><tr><td>Add an investor to whitelist</td><td>&quot;Add 0xabc…123 to <code>&lt;TOKEN&gt;</code>&#39;s whitelist.&quot;</td></tr><tr><td>Add an accredited investor</td><td>&quot;Add 0xabc…123 to <code>&lt;TOKEN&gt;</code>&#39;s whitelist as tier 2 accredited.&quot;</td></tr><tr><td>Remove an investor</td><td>&quot;Remove 0xdef…456 from <code>&lt;TOKEN&gt;</code>.&quot;</td></tr><tr><td>Verify membership</td><td>&quot;Is 0xabc…123 on <code>&lt;TOKEN&gt;</code>&#39;s whitelist?&quot;</td></tr><tr><td>Bulk adds</td><td>&quot;Add the following addresses to <code>&lt;TOKEN&gt;</code>: 0xabc…, 0xdef…, 0x123…&quot; <em>(HavenBot prompts you per address)</em></td></tr></tbody></table><p>Tier 1 = retail KYC (one <code>addToWhitelist</code> UserOp). Tier 2 = accredited (two sequential UserOps: <code>addToWhitelist</code> + <code>addToAccreditedList</code>).</p><p>Removal <strong>auto-clears</strong> the tier-2 accredited flag — see <code>ERC3643KYCAdapter.sol:103-110</code>.</p><div class="warning custom-block"><p class="custom-block-title">KYC bypass in dev mode</p><p>For the hackathon, MuHavenIdentityRegistry runs in dev mode (<code>devMode=true</code> → <code>isVerified</code> always returns true, no whitelist enforcement). KYC tools work but the on-chain compliance check is bypassed until production KYC partners are wired.</p></div><h2 id="unpause-a-freshly-deployed-token" tabindex="-1">Unpause a freshly-deployed token <a class="header-anchor" href="#unpause-a-freshly-deployed-token" aria-label="Permalink to &quot;Unpause a freshly-deployed token&quot;">​</a></h2><p>When you complete the F2 token-creation wizard, the new token is <strong>paused</strong> by default. To activate it, you need to set its initial NAV and flip <code>paused = false</code>. HavenBot does both in one signed action:</p><table tabindex="0"><thead><tr><th>You want</th><th>Say</th></tr></thead><tbody><tr><td>Activate a new token</td><td>&quot;<code>&lt;TOKEN&gt;</code>&#39;s first NAV came in at $0.998 — set NAV and unpause.&quot;</td></tr><tr><td>Re-quote and activate</td><td>&quot;What&#39;s the suggested initial NAV for <code>&lt;TOKEN&gt;</code>? Then activate.&quot; <em>(HavenBot reads the off-chain price feed and proposes the value)</em></td></tr><tr><td>Inspect status</td><td>&quot;Is <code>&lt;TOKEN&gt;</code> active or still paused?&quot;</td></tr></tbody></table><p>This calls <code>muhaven_propose_unpause_token</code>, which signs <strong>two UserOps</strong> with your issuer passkey:</p><ol><li><code>IssuerControlledOracle.setNAV(token, initialNav)</code> — writes the first NAV.</li><li><code>TokenRegistry.setPaused(token, false)</code> — flips the paused flag.</li></ol><p>Both signed by your <strong>issuer passkey</strong> (production-trajectory shape — NOT the deployer-side <code>scripts/unpause-token.ts</code> automation that exists for dev convenience).</p><p>The tool is <strong>idempotent</strong>: if the token is already unpaused, HavenBot refuses with <code>409 ALREADY_ACTIVE</code> instead of re-issuing the UserOps.</p><h2 id="audit-copilot" tabindex="-1">Audit copilot <a class="header-anchor" href="#audit-copilot" aria-label="Permalink to &quot;Audit copilot&quot;">​</a></h2><table tabindex="0"><thead><tr><th>You want</th><th>Say</th></tr></thead><tbody><tr><td>Recent issuer audit</td><td>&quot;Show my issuer audit log.&quot;</td></tr><tr><td>Filter by surface</td><td>&quot;Show audit rows that came from MCP.&quot;</td></tr><tr><td>Filter by tool</td><td>&quot;Show every distribute_yield I&#39;ve run this month.&quot;</td></tr><tr><td>Filter by token</td><td>&quot;Show audit for <code>&lt;TOKEN&gt;</code> this quarter.&quot;</td></tr><tr><td>Export</td><td>&quot;Export my issuer audit log for the last 90 days.&quot;</td></tr></tbody></table><p>Issuer audit is <strong>self-only with a 90-day window cap</strong>.</p><h2 id="create-a-hosted-checkout-link" tabindex="-1">Create a hosted-checkout link <a class="header-anchor" href="#create-a-hosted-checkout-link" aria-label="Permalink to &quot;Create a hosted-checkout link&quot;">​</a></h2><p>The hosted-checkout surface at <code>muhaven.app/pay/...</code> is operated entirely from the issuer side via HavenBot:</p><table tabindex="0"><thead><tr><th>You want</th><th>Say</th></tr></thead><tbody><tr><td>Create a one-off pay link</td><td>&quot;Create a checkout link for 500 mhUSDC of <code>&lt;TOKEN&gt;</code> expiring in 24 hours.&quot;</td></tr><tr><td>With a custom label</td><td>&quot;Create a checkout link for 1000 mhUSDC of <code>&lt;TOKEN&gt;</code> for buyer &#39;Acme Treasury&#39;.&quot;</td></tr><tr><td>With a webhook</td><td>&quot;Create a checkout link for 200 mhUSDC of <code>&lt;TOKEN&gt;</code> with webhook <a href="https://my.api/cb." target="_blank" rel="noreferrer">https://my.api/cb.</a>&quot;</td></tr><tr><td>Inspect status</td><td>&quot;What&#39;s the status of checkout <code>chk_01HMTV…</code>?&quot;</td></tr><tr><td>List recent</td><td>&quot;Show my recent checkouts.&quot; or &quot;Show my pending checkouts.&quot;</td></tr><tr><td>Cancel an unredeemed link</td><td>&quot;Cancel checkout <code>chk_01HMTV…</code>.&quot;</td></tr></tbody></table><p>The link HavenBot returns has the <strong>fragment-key</strong> structure — the key is in the URL fragment so it never reaches our server. See <a href="/checkout/fragment-key">URL fragment key (privacy)</a>.</p><p>The buyer follows the link, pays with their own passkey, and the SSE channel pushes you a real-time &quot;Paid&quot; notification.</p><h2 id="what-about-token-creation" tabindex="-1">What about token creation? <a class="header-anchor" href="#what-about-token-creation" aria-label="Permalink to &quot;What about token creation?&quot;">​</a></h2><p>Token creation (the F2 wizard) is <strong>not</strong> in HavenBot. It&#39;s a multi-step dashboard wizard at <code>/issuer/tokens/new</code> because it needs uploads, jurisdictional metadata, and a registry-deploy step that doesn&#39;t fit a single tool call.</p><p>HavenBot picks up where the F2 wizard ends: at step 6 (set initial NAV + unpause), <code>muhaven_propose_unpause_token</code> is the natural handoff.</p><h2 id="what-havenbot-won-t-do-for-issuers" tabindex="-1">What HavenBot won&#39;t do for issuers <a class="header-anchor" href="#what-havenbot-won-t-do-for-issuers" aria-label="Permalink to &quot;What HavenBot won&#39;t do for issuers&quot;">​</a></h2><ul><li><strong>It won&#39;t move yield from your treasury to a non-investor wallet.</strong> Yield distribution targets MuHavenEscrow contracts only; the issuer&#39;s MuHaven wallet can&#39;t divert.</li><li><strong>It won&#39;t decrypt investor balances.</strong> The issuer sees aggregates (total supply <em>handle</em>, holder count) — never per-investor amounts.</li><li><strong>It won&#39;t auto-approve KYC.</strong> Every add/remove is a deliberate signed action.</li><li><strong>It won&#39;t act as another issuer.</strong> Cross-issuer audit access requires a permit signed by the other issuer.</li></ul><h2 id="common-mistakes" tabindex="-1">Common mistakes <a class="header-anchor" href="#common-mistakes" aria-label="Permalink to &quot;Common mistakes&quot;">​</a></h2><ul><li><strong>&quot;Distribute yield to my token&quot;</strong> without specifying which token → HavenBot asks which one.</li><li><strong>&quot;Add this whitelist&quot;</strong> with a list pasted as plaintext → HavenBot parses one address at a time and prompts you per row.</li><li><strong>&quot;Unpause <code>&lt;TOKEN&gt;</code>&quot;</strong> without specifying initial NAV → HavenBot will quote from the oracle but ask you to confirm; setting NAV is a signed action you don&#39;t want auto-defaulted.</li></ul><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/havenbot/investor-playbook">Investor playbook</a> — the investor-side phrasing.</li><li><a href="/checkout/for-issuers">Hosted Checkout for issuers</a> — the create-link flow end-to-end.</li><li><a href="/policy/audit-log">Audit log</a> — what&#39;s logged and how to query it.</li></ul>',42)])])}const y=e(s,[["render",d]]);export{p as __pageData,y as default};
